import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../api/axios";

export default function VerifyBooking() {
    const { bookingId } = useParams();
    const navigate = useNavigate();
    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    useEffect(() => {
        const fetchBooking = async () => {
            try {
                const res = await axios.get(`/bookings/${bookingId}`);
                setBooking(res.data);
                setLoading(false);
            } catch (err) {
                console.error("Verification failed", err);
                if (err.response && (err.response.status === 401 || err.response.status === 403)) {
                    setError("Unauthorized: Please Login as Admin or Owner");
                } else {
                    setError("Booking Not Found or Invalid");
                }
                setLoading(false);
            }
        };
        fetchBooking();
    }, [bookingId]);

    if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Verifying Booking...</div>;

    if (error) {
        return (
            <div style={{ textAlign: "center", marginTop: "50px", color: "#c62828" }}>
                <h2>❌ Verification Failed</h2>
                <p>{error}</p>
                <button onClick={() => navigate("/login")} style={{ padding: "10px 20px", marginTop: "20px", cursor: "pointer" }}>Login to Verify</button>
            </div>
        );
    }

    const isValid = booking.status === "Active" || booking.status === "Completed";
    const isPaid = booking.paymentStatus === "Paid";

    return (
        <div className="auth-container" style={{ padding: "40px 20px" }}>
            <div style={{ background: "var(--glass-bg)", backdropFilter: "var(--glass-blur)", borderRadius: "20px", border: "1px solid rgba(255,255,255,0.05)", boxShadow: isValid && isPaid ? "0 0 40px rgba(0, 255, 136, 0.2)" : "0 0 40px rgba(255, 42, 95, 0.2)", maxWidth: "550px", width: "100%", overflow: "hidden" }}>

                {/* Status Header */}
                <div style={{
                    background: isValid && isPaid ? "rgba(0, 255, 136, 0.1)" : "rgba(255, 42, 95, 0.1)",
                    borderBottom: isValid && isPaid ? "2px solid var(--accent-green)" : "2px solid var(--accent-pink)",
                    padding: "35px 20px",
                    textAlign: "center",
                    color: "white"
                }}>
                    <h1 style={{ margin: 0, fontSize: "2.8rem", color: isValid && isPaid ? "var(--accent-green)" : "var(--accent-pink)", textShadow: isValid && isPaid ? "var(--shadow-neon-green)" : "var(--shadow-neon-pink)", letterSpacing: "3px" }}>
                        {isValid && isPaid ? "SYSTEM AUTHORIZED" : "ACCESS DENIED"}
                    </h1>
                    <p style={{ margin: "10px 0 0", color: "var(--text-secondary)", letterSpacing: "2px", fontWeight: "bold" }}>
                        {isPaid ? "PAYMENT VERIFIED • STATUS LOGGED" : "PAYMENT PENDING / FAILED OR EXPIRED"}
                    </p>
                </div>

                {/* Details */}
                <div style={{ padding: "35px" }}>
                    <h3 style={{ borderBottom: "1px solid rgba(255,255,255,0.1)", paddingBottom: "15px", color: "var(--accent-cyan)", letterSpacing: "2px", fontSize: "1.1rem" }}>📋 RESERVATION LOGS</h3>

                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "25px", marginBottom: "30px" }}>
                        <div className="card" style={{ padding: "15px" }}>
                            <div style={labelStyle}>VEHICLE ID</div>
                            <div style={valueStyle}>{booking.vehicleNumber}</div>
                        </div>
                        <div className="card" style={{ padding: "15px" }}>
                            <div style={labelStyle}>CLASS</div>
                            <div style={valueStyle}>{booking.vehicleType}</div>
                        </div>
                        <div className="card" style={{ padding: "15px" }}>
                            <div style={labelStyle}>SECTOR</div>
                            <div style={valueStyle}>{booking.slotId?.parkingLotId?.name || "Unknown"}</div>
                        </div>
                        <div className="card" style={{ padding: "15px" }}>
                            <div style={labelStyle}>BAY</div>
                            <div style={valueStyle}>{booking.slotId?.slotNumber}</div>
                        </div>
                    </div>

                    <div className="card" style={{ padding: "20px", marginBottom: "30px", background: "rgba(0, 240, 255, 0.05)", border: "1px solid rgba(0, 240, 255, 0.2)" }}>
                        <div style={labelStyle}>ALLOCATED TIMEFRAME</div>
                        <div style={{ color: "white", fontWeight: "bold", fontSize: "1.2rem", marginTop: "10px", lineHeight: "1.5" }}>
                            {new Date(booking.startTime).toLocaleString()} <br />
                            <span style={{ color: "var(--accent-cyan)", fontSize: "0.8em", margin: "5px 0", display: "inline-block" }}>UNTIL</span> <br />
                            {new Date(booking.endTime).toLocaleString()}
                        </div>
                    </div>

                    <h3 style={{ borderBottom: "1px solid rgba(255,255,255,0.1)", paddingBottom: "15px", color: "var(--accent-cyan)", letterSpacing: "2px", fontSize: "1.1rem" }}>👤 REGISTERED ENTITY</h3>
                    <div style={{ display: "flex", gap: "15px", alignItems: "center", background: "rgba(255,255,255,0.02)", padding: "20px", borderRadius: "15px", border: "1px solid rgba(255,255,255,0.05)" }}>
                        <div style={{ background: "var(--accent-purple)", color: "white", width: "50px", height: "50px", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.5rem", fontWeight: "bold", boxShadow: "var(--shadow-neon-purple)" }}>
                            {booking.userId?.name?.charAt(0) || "U"}
                        </div>
                        <div>
                            <div style={{ fontWeight: "bold", color: "var(--text-primary)", fontSize: "1.2rem" }}>{booking.userId?.name}</div>
                            <div style={{ fontSize: "0.95em", color: "var(--text-secondary)", marginTop: "3px" }}>{booking.userId?.email}</div>
                        </div>
                    </div>

                </div>

                {/* Footer Action */}
                <div style={{ background: "rgba(0,0,0,0.2)", padding: "25px", textAlign: "center", borderTop: "1px solid rgba(255,255,255,0.05)" }}>
                    <button onClick={() => navigate("/")} className="btn-primary" style={{ padding: "12px 30px", background: "transparent", border: "1px solid var(--text-secondary)", color: "var(--text-primary)", boxShadow: "none" }}>RETURN TO BASE</button>
                </div>
            </div>
        </div>
    );
}

const labelStyle = { color: "var(--text-secondary)", fontSize: "0.75em", textTransform: "uppercase", marginBottom: "8px", letterSpacing: "2px" };
const valueStyle = { color: "var(--text-primary)", fontWeight: "bold", fontSize: "1.3em" };
